{{ config(materialized=\'table\') }}\n\nSELECT\n    op.opp_kennung AS \"Id\",\n    COALESCE(op.titel, \'Unknown Opportunity Name\') AS \"Name\", -- Name is NOT NULL\n    CASE\n        WHEN LOWER(op.vertriebsphase) = \'prospecting\' THEN \'Prospecting\'\n        WHEN LOWER(op.vertriebsphase) = \'qualification\' THEN \'Qualification\'\n        WHEN LOWER(op.vertriebsphase) = \'needs analysis\' THEN \'Needs Analysis\'\n        WHEN LOWER(op.vertriebsphase) = \'value proposition\' THEN \'Value Proposition\'\n        WHEN LOWER(op.vertriebsphase) = \'id. decision makers\' THEN \'Id. Decision Makers\'\n        WHEN LOWER(op.vertriebsphase) = \'perception analysis\' THEN \'Perception Analysis\'\n        WHEN LOWER(op.vertriebsphase) = \'proposal/price quote\' THEN \'Proposal/Price Quote\'\n        WHEN LOWER(op.vertriebsphase) = \'negotiation/review\' THEN \'Negotiation/Review\'\n        WHEN LOWER(op.vertriebsphase) = \'closed won\' THEN \'Closed Won\'\n        WHEN LOWER(op.vertriebsphase) = \'closed lost\' THEN \'Closed Lost\'\n        ELSE \'Prospecting\' -- StageName is NOT NULL, fallback\n    END AS \"StageName\",\n    COALESCE(\n        TO_CHAR(TO_DATE(op.zieldatum, \'YYYY-MM-DD\'), \'YYYY-MM-DD\'),\n        TO_CHAR(TO_DATE(op.zieldatum, \'DD.MM.YYYY\'), \'YYYY-MM-DD\'),\n        TO_CHAR(TO_DATE(op.zieldatum, \'MM/DD/YYYY\'), \'YYYY-MM-DD\'),\n        TO_CHAR(TO_DATE(op.zieldatum, \'YYYYMMDD\'), \'YYYY-MM-DD\'),\n        TO_CHAR(CURRENT_DATE, \'YYYY-MM-DD\') -- CloseDate is NOT NULL, fallback\n    ) AS \"CloseDate\",\n    CAST(\n        CASE\n            WHEN op.auftragswert IS NULL OR TRIM(op.auftragswert) = \'\' THEN NULL\n            -- European format: remove dots, replace comma with dot\n            WHEN TRIM(op.auftragswert) ~ \'^[0-9\s\.]*\,[0-9]{1,2}$\' THEN\n                REPLACE(REPLACE(TRIM(REGEXP_REPLACE(op.auftragswert, \'[^0-9,\.]\', \'\', \'g\')), \'.\', \'\'), \',\', \'.\')\n            -- US/standard format: remove commas, use dot as is\n            WHEN TRIM(op.auftragswert) ~ \'^[0-9\s\,]*\.[0-9]{1,2}$\' THEN\n                REPLACE(TRIM(REGEXP_REPLACE(op.auftragswert, \'[^0-9\.]\', \'\', \'g\')), \',\', \'\')\n            -- Integer or plain number without specific decimal/thousand separators\n            WHEN TRIM(op.auftragswert) ~ \'^[0-9\s]*$\' THEN\n                TRIM(REGEXP_REPLACE(op.auftragswert, \'[^\d]\', \'\', \'g\'))\n            ELSE NULL\n        END\n    AS DOUBLE PRECISION) AS \"Amount\",\n    op.waehrungscode AS \"CurrencyIsoCode\",\n    mak.kundennummer AS \"AccountId\", -- Join on kunden_ref and kundennummer\n    op.opp_kennung AS \"Legacy_Opportunity_ID__c\",\n    NULL AS \"CreatedDate\",\n    NULL AS \"LastModifiedDate\",\n    0 AS \"IsDeleted\"\nFROM\n    {{ source(\'fixture_master_v2_src\', \'master_opportunities\') }} AS op\nLEFT JOIN\n    {{ source(\'fixture_master_v2_src\', \'master_kunden\') }} AS mak\n    ON op.kunden_ref = mak.kundennummer\n